1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge cases / simplest
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // Base premiums for main items (each + 5 G fee)
15	  it.todo("single sword → premium 105 G (100 base + 5 fee)");
16	  it.todo("single amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("single staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("single potion → premium 45 G (40 base + 5 fee)");
19	
20	  // Component pricing
21	  it.todo("2 runes → 50 G base premium (55 G with fee)");
22	  it.todo("3 runes → 60 G base premium block (65 G with fee)");
23	  it.todo("4 runes → 100 G base premium no block (105 G with fee)");
24	  it.todo("7 runes → 175 G base premium (one block of 3 + 4 singles = 60 + 100; 180 G with fee)");
25	
26	  // "Alike" components clarification
27	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
28	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
29	
30	  // Item-specific modifiers
31	  it.todo("cursed sword adds 50% risk surcharge → 100 + 50 = 150 base, 155 with fee");
32	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge → 130 base, 135 with fee");
33	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (100 base, 105 with fee)");
34	  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 = 180, 185 with fee)");
35	
36	  // Policy-wide modifiers
37	  it.todo("first insurance adds 10% to policy → sword 100 + 10 = 110, 115 with fee");
38	  it.todo("loyalty discount: customer with exactly 2 years → 20% off policy");
39	  it.todo("follow-up contract: second quote in scenario gets 15% discount");
40	
41	  // Modifier scope on multi-item policies
42	  it.todo("policy with cursed sword + plain amulet → cursed surcharge only on sword's base premium (160 + 50 = 210 before fee and other modifiers)");
43	
44	  // Rounding
45	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
46	
47	  // Integration examples
48	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
49	  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years → 160 G");
50	
51	  // Claim: standard reimbursement
52	  it.todo("regular sword damage 500 G → payout 400 G (deductible 100)");
53	  it.todo("rune damage 200 G → payout 100 G (no special clauses, deductible)");
54	
55	  // Enchantment threshold vs dragon material
56	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% rule + deductible)");
57	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
58	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement minus deductible)");
59	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
60	
61	  // Deductible per damage event
62	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
63	
64	  // Multiple items of same type
65	  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
66	  it.todo("two sword damages with two swords insured → each treated as separate damage with own deductible");
67	  it.todo("damages contain more entries of a type than insured (2 sword damages, 1 sword) → claim rejected (error)");
68	
69	  // Cap exhaustion
70	  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
71	  it.todo("cursed sword (premium with modifiers 165) → cap 2000 (based on unmodified insurance value)");
72	  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
73	  it.todo("sword cap 2000, two claims of 1500 each → first payout 1400 (cap 600 remaining), second payout 600 (cap 0)");
74	
75	  // Payout rounding
76	  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");
77	
78	  // Edge cases / errors
79	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
80	  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
81	  it.todo("claim contains damage with negative amount → CLI exits non-zero, error to stderr");
